def remove_duplicates(numbers: List[int]) -> List[int]:
    """ Given a list of integers, remove all elements that have duplicates. The output list should have the same order for the elements that are kept. """
    unique_numbers = []
    duplicates = set()

    for num in numbers:
        if num in duplicates:
            continue
        if num in unique_numbers:
            unique_numbers.remove(num)
            duplicates.add(num)
        else:
            unique_numbers.append(num)

    return unique_numbers
